#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>
#include <string.h>
#include <string>
#include <sys/time.h>

#include "common.h"
#include <cuda_runtime.h>

#define BLOCK_SIZE 16

static int do_verify = 0;

static struct option long_options[] = {
    {"input", 1, NULL, 'i'},
    {"size", 1, NULL, 's'},
    {"verify", 0, NULL, 'v'},
    {"platform", 1, NULL, 'p'},
    {"device", 1, NULL, 'd'},
    {0, 0, 0, 0}
};

extern "C" void lud_diagonal(float *m, float *shadow, int matrix_dim, int offset);
extern "C" void lud_perimeter(float *m, float *dia, float *peri_row, float *peri_col, int matrix_dim, int offset);
extern "C" void lud_internal(float *m, float *peri_row, float *peri_col, int matrix_dim, int offset);

int main(int argc, char *argv[])
{
    size_t matrix_dim = 32;
    int opt, option_index = 0;
    func_ret_t ret;
    const char *input_file = NULL;
    float *m, *mm;
    stopwatch sw;

    while ((opt = getopt_long(argc, argv, "::vs:i:p:d:",
                              long_options, &option_index)) != -1) {
        switch (opt) {
        case 'i':
            input_file = optarg;
            break;
        case 'v':
            do_verify = 1;
            break;
        case 's':
            matrix_dim = atoi(optarg);
            printf("Generate input matrix internally, size =%lu\n", matrix_dim);
            break;
        case 'p':
            // platform_id_inuse ignored in CUDA version
            break;
        case 'd':
            // device_id_inuse ignored in CUDA version
            break;
        case '?':
            fprintf(stderr, "invalid option\n");
            break;
        case ':':
            fprintf(stderr, "missing argument\n");
            break;
        default:
            fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
                    argv[0]);
            exit(EXIT_FAILURE);
        }
    }

    if ((argc > optind) || (1 == optind)) {
        fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
        exit(EXIT_FAILURE);
    }

    if (input_file) {
        printf("Reading matrix from file %s\n", input_file);
        ret = create_matrix_from_file(&m, input_file, &matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix from file %s\n", input_file);
            exit(EXIT_FAILURE);
        }
    }
    else if (matrix_dim) {
        printf("Creating matrix internally size=%lu\n", matrix_dim);
        ret = create_matrix(&m, matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix internally size=%lu\n", matrix_dim);
            exit(EXIT_FAILURE);
        }
    }
    else {
        printf("No input file specified!\n");
        exit(EXIT_FAILURE);
    }

    if (do_verify) {
        printf("Before LUD\n");
        matrix_duplicate(m, &mm, matrix_dim);
    }

    // Allocate device memory
    float *d_m;
    cudaError_t err = cudaMalloc((void **)&d_m, matrix_dim * matrix_dim * sizeof(float));
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }

    // Copy matrix to device
    err = cudaMemcpy(d_m, m, matrix_dim * matrix_dim * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy H2D failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_m);
        exit(EXIT_FAILURE);
    }

    stopwatch_start(&sw);

    size_t i = 0;
    for (i = 0; matrix_dim - BLOCK_SIZE > i; i += BLOCK_SIZE) {
        // lud_diagonal kernel launch
        {
            dim3 dimBlock(BLOCK_SIZE, 1, 1);
            dim3 dimGrid(1, 1, 1);
            size_t shared_mem_size = BLOCK_SIZE * BLOCK_SIZE * sizeof(float);
            lud_diagonal<<<dimGrid, dimBlock, shared_mem_size>>>(d_m, NULL, matrix_dim, i);
            err = cudaGetLastError();
            if (err != cudaSuccess) {
                fprintf(stderr, "lud_diagonal kernel launch failed: %s\n", cudaGetErrorString(err));
                cudaFree(d_m);
                exit(EXIT_FAILURE);
            }
            cudaDeviceSynchronize();
        }

        // lud_perimeter kernel launch
        {
            int num_blocks = (int)((matrix_dim - i) / BLOCK_SIZE - 1);
            if (num_blocks > 0) {
                dim3 dimBlock(BLOCK_SIZE * 2, 1, 1);
                dim3 dimGrid(num_blocks, 1, 1);
                size_t shared_mem_size = 3 * BLOCK_SIZE * BLOCK_SIZE * sizeof(float);
                lud_perimeter<<<dimGrid, dimBlock, shared_mem_size>>>(d_m, NULL, NULL, NULL, matrix_dim, i);
                err = cudaGetLastError();
                if (err != cudaSuccess) {
                    fprintf(stderr, "lud_perimeter kernel launch failed: %s\n", cudaGetErrorString(err));
                    cudaFree(d_m);
                    exit(EXIT_FAILURE);
                }
                cudaDeviceSynchronize();
            }
        }

        // lud_internal kernel launch
        {
            int num_blocks = (int)((matrix_dim - i) / BLOCK_SIZE - 1);
            if (num_blocks > 0) {
                dim3 dimBlock(BLOCK_SIZE, BLOCK_SIZE, 1);
                dim3 dimGrid(num_blocks, num_blocks, 1);
                size_t shared_mem_size = 2 * BLOCK_SIZE * BLOCK_SIZE * sizeof(float);
                lud_internal<<<dimGrid, dimBlock, shared_mem_size>>>(d_m, NULL, NULL, matrix_dim, i);
                err = cudaGetLastError();
                if (err != cudaSuccess) {
                    fprintf(stderr, "lud_internal kernel launch failed: %s\n", cudaGetErrorString(err));
                    cudaFree(d_m);
                    exit(EXIT_FAILURE);
                }
                cudaDeviceSynchronize();
            }
        }
    }

    // Final lud_diagonal kernel launch for last block
    {
        dim3 dimBlock(BLOCK_SIZE, 1, 1);
        dim3 dimGrid(1, 1, 1);
        size_t shared_mem_size = BLOCK_SIZE * BLOCK_SIZE * sizeof(float);
        lud_diagonal<<<dimGrid, dimBlock, shared_mem_size>>>(d_m, NULL, matrix_dim, i);
        err = cudaGetLastError();
        if (err != cudaSuccess) {
            fprintf(stderr, "final lud_diagonal kernel launch failed: %s\n", cudaGetErrorString(err));
            cudaFree(d_m);
            exit(EXIT_FAILURE);
        }
        cudaDeviceSynchronize();
    }

    stopwatch_stop(&sw);

    // Copy result back to host
    err = cudaMemcpy(m, d_m, matrix_dim * matrix_dim * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy D2H failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_m);
        exit(EXIT_FAILURE);
    }

    cudaFree(d_m);

    if (do_verify) {
        printf("After LUD\n");
        printf(">>>Verify<<<<\n");
        lud_verify(mm, m, matrix_dim);
        free(mm);
    }

    free(m);

    return 0;
}
